// Format comprehensive monitoring report
const dailySummaryRaw = $input.first().json;
const problemAreasRaw = $input.item(1).json;
const realtimeMetricsRaw = $input.last().json;

// Handle single object vs array
const dailySummary = Array.isArray(dailySummaryRaw) ? dailySummaryRaw : [dailySummaryRaw];
const problemAreas = Array.isArray(problemAreasRaw) ? problemAreasRaw : [problemAreasRaw];
const realtimeMetrics = Array.isArray(realtimeMetricsRaw) ? realtimeMetricsRaw : [realtimeMetricsRaw];

// Process real-time metrics
const metrics = {};
realtimeMetrics.forEach(metric => {
  metrics[metric.time_period] = {
    discrepancies: metric.discrepancies_last_hour || metric.discrepancies_today || metric.pending_items || 0,
    high_severity: metric.high_severity_last_hour || metric.high_severity_today || metric.high_severity_pending || 0,
    revenue_impact: parseFloat(metric.revenue_impact_last_hour || metric.revenue_impact_today || metric.pending_revenue_impact || 0)
  };
});

// Calculate trends
const today = dailySummary.find(d => d.report_date === new Date().toISOString().split('T')[0]);
const yesterday = dailySummary.find(d => {
  const yesterdayDate = new Date();
  yesterdayDate.setDate(yesterdayDate.getDate() - 1);
  return d.report_date === yesterdayDate.toISOString().split('T')[0];
});

const trend = {
  discrepancy_change: today && yesterday && yesterday.total_discrepancies > 0 ? 
    ((today.total_discrepancies - yesterday.total_discrepancies) / yesterday.total_discrepancies * 100).toFixed(1) : 'N/A',
  revenue_impact_change: today && yesterday && Math.abs(yesterday.total_revenue_impact) > 0 ? 
    ((today.total_revenue_impact - yesterday.total_revenue_impact) / Math.abs(yesterday.total_revenue_impact) * 100).toFixed(1) : 'N/A'
};

// Determine alert level
let alertLevel = 'GREEN';
let alertMessages = [];

if (metrics.current_hour?.high_severity > 0) {
  alertLevel = 'RED';
  alertMessages.push(`🚨 ${metrics.current_hour.high_severity} high severity issues in the last hour`);
}

if (metrics.current_hour?.discrepancies > 50) {
  alertLevel = alertLevel === 'RED' ? 'RED' : 'ORANGE';
  alertMessages.push(`⚠️ High volume: ${metrics.current_hour.discrepancies} discrepancies in the last hour`);
}

if (metrics.pending_review?.high_severity > 10) {
  alertLevel = alertLevel === 'RED' ? 'RED' : 'ORANGE';
  alertMessages.push(`📋 ${metrics.pending_review.high_severity} high severity items pending review`);
}

if (metrics.pending_review?.discrepancies > 100) {
  alertLevel = alertLevel === 'RED' ? 'RED' : 'ORANGE';
  alertMessages.push(`⚠️ Large backlog: ${metrics.pending_review.discrepancies} items pending review`);
}

// Format currency values
const formatCurrency = (amount) => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 2
  }).format(amount || 0);
};

// Create comprehensive report
const report = {
  timestamp: new Date().toISOString(),
  alert_level: alertLevel,
  alert_messages: alertMessages,

  executive_summary: {
    last_hour: {
      total_discrepancies: metrics.current_hour?.discrepancies || 0,
      high_severity: metrics.current_hour?.high_severity || 0,
      revenue_impact: formatCurrency(metrics.current_hour?.revenue_impact)
    },
    today: {
      total_discrepancies: metrics.current_day?.discrepancies || 0,
      high_severity: metrics.current_day?.high_severity || 0,
      revenue_impact: formatCurrency(metrics.current_day?.revenue_impact)
    },
    pending_review: {
      total_items: metrics.pending_review?.discrepancies || 0,
      high_severity: metrics.pending_review?.high_severity || 0,
      revenue_impact: formatCurrency(metrics.pending_review?.revenue_impact)
    },
    trends: trend
  },

  daily_breakdown: dailySummary.map(day => ({
    date: day.report_date,
    total_discrepancies: day.total_discrepancies || 0,
    severity_breakdown: {
      high: day.high_severity || 0,
      medium: day.medium_severity || 0,
      low: day.low_severity || 0
    },
    revenue_impact: {
      total: formatCurrency(day.total_revenue_impact),
      overcharge: formatCurrency(day.revenue_overcharge),
      undercharge: formatCurrency(day.revenue_undercharge)
    },
    resolution_status: {
      resolved: day.resolved_count || 0,
      pending: day.pending_review || 0
    }
  })),

  problem_areas: problemAreas.map(area => ({
    service: `${area.revenue_line} (${area.currency})`,
    discrepancy_count: area.discrepancy_count || 0,
    avg_variance_percentage: `${(area.avg_variance_pct || 0).toFixed(2)}%`,
    total_impact: formatCurrency(area.total_impact),
    high_severity_count: area.high_severity_count || 0,
    priority: (area.high_severity_count || 0) > 0 ? 'HIGH' : 
             (area.discrepancy_count || 0) > 20 ? 'MEDIUM' : 'LOW'
  })),

  recommendations: []
};

// Generate actionable recommendations
if (problemAreas.length > 0) {
  const topProblem = problemAreas[0];
  report.recommendations.push(
    `📊 Focus on "${topProblem.revenue_line}" - ${topProblem.discrepancy_count} discrepancies with ${formatCurrency(topProblem.total_impact)} impact`
  );
}

if (metrics.pending_review?.discrepancies > 20) {
  report.recommendations.push(
    `⏰ Priority: Review ${metrics.pending_review.discrepancies} pending discrepancies (${formatCurrency(metrics.pending_review.revenue_impact)} at risk)`
  );
}

if (trend.discrepancy_change !== 'N/A' && parseFloat(trend.discrepancy_change) > 25) {
  report.recommendations.push(
    `📈 Investigate ${trend.discrepancy_change}% increase in discrepancies compared to yesterday`
  );
}

if (trend.discrepancy_change !== 'N/A' && parseFloat(trend.discrepancy_change) < -25) {
  report.recommendations.push(
    `✅ Positive trend: ${Math.abs(parseFloat(trend.discrepancy_change))}% decrease in discrepancies`
  );
}

return [{ json: { report } }];

